#!/usr/bin/env perl

use strict;
use warnings;

my $redirect_url = "";

if (exists($ENV{"QUERY_STRING"}) && defined($ENV{"QUERY_STRING"})) {
    my @params = split("&", $ENV{"QUERY_STRING"});
    foreach my $param (@params) {
        if ($param =~ /^next=/) {
            $redirect_url = substr($param, 5);
            last;
        }
    }
}

if ($redirect_url ne "") {
    print "Location: $redirect_url\n\n";
} else {
    print "Content-Type: text/html\n\n";
    print "<html><body>Invalid redirect URL</body></html>";
}